const serviceName = variables.service;
if(serviceName !== "") {
  const searchedService = filteredServices.value.find(obj => obj.serviceName === serviceName);

  // If service exists in CP, set service name, details and fetch rate limit and configs.
  if(searchedService) {
    components.allServicesContainer.setTab("t1"); 
    await actions.setPageVariable("selectedServiceRow",searchedService)
    await actions.setPageVariable("selectedService",serviceName)
    await queries.fetchAllConfigs.run();
    await queries.fetchRateLimit.run();
  } else {
    components.allServicesContainer.setTab("t0");
    utils.showNotification({
        title: "Wrong Service Name",
        description: "Service you're trying to open doesn't exist.",
        notificationType: "error"
      }
    );
    return;
  }
}
